Hi @tleonhardt, as always many thanks for the great answer.  I made a short example and it works for me. Do you see anything I could do in a more pythonic way?

```python

import abc
import inspect

from cmd2 import Cmd


class Base(metaclass=abc.ABCMeta):
    def get_do_functions(self):
        return_list = []
        for name, func in inspect.getmembers(self, predicate=inspect.ismethod):
            if name.startswith("do_"):
                return_list.append((name, func))
        return return_list


class A(Base):

    def __init__(self, a):
        self.a = a

    def do_fa(self, args):
        print("hello from class A fa with args: % and instance var a: %", args, self.a)


class B(Base):

    def __init__(self, b):
        self.b = b
        self.b1 = b * 2

    def do_fb(self, args):
        print("hello from class B fb with args: % and instance var b: %", args, self.b)

    def do_fb1(self, args):
        print("hello from class B fb1 with args: % and instance var b: %", args, self.b1)


class C(Base):

    def __init__(self, c):
        self.c = c

    def do_func_c_long_name(self, args):
        print("hello from class C fc with args: % and instance var c: %", args, self.c)

    do_fc = do_func_c_long_name


def append_do_methods(object_to_inspect, cmd_object):
    for func in object_to_inspect.get_do_functions():
        setattr(cmd_object, func[0], func[1])


if __name__ == '__main__':
    obj_a = A(1)
    obj_b = B(2)
    obj_c = C(3)

    append_do_methods(obj_a, Cmd)
    append_do_methods(obj_b, Cmd)
    append_do_methods(obj_c, Cmd)

    app = Cmd()
    app.cmdloop()

```

